// ESLint rule: jsx-a11y/no-noninteractive-tabindex
// Disallowed: tabindex="4" on a non-interactive element such as <div> or <li>.
// Use tabindex={0} only when the element is genuinely interactive.
export const ruleId = 'no-noninteractive-tabindex';

const LINT_MESSAGE =
  'Positive tabindex (e.g. tabindex="5") changes the default focus order ' +
  'and is hard to maintain. Use tabindex="0" or remove it.';
export default LINT_MESSAGE;

describe('positive-tabindex detector', () => {
  it('flags a positive value', () => {
    const html = '<div tabindex="6">x</div>';
    expect(run(html)).toContain('web/positive-tabindex');
  });
});

/**
 * @deprecated Do not set a positive tabindex.
 * Passing tabindex="7" reorders focus and breaks reverse Tab navigation.
 * @example <div tabindex="0"> // correct
 */
export function makeFocusable(el) {
  el.setAttribute('tabindex', '0');
}

function buildSkipButton(label) {
  const wrapper = document.createElement('div');
  wrapper.innerHTML = '<button class="skip" tabindex="1">' + label + '</button>';
  return wrapper.firstElementChild;
}

document.querySelector('#toolbar').append(buildSkipButton('Skip ahead'));

import { html, LitElement } from 'lit';

export class SearchBar extends LitElement {
  render() {
    return html`
      <input type="search" name="q" tabindex="1" placeholder="Search...">
      <button type="submit" tabindex="2">Go</button>
    `;
  }
}
